<div class="module-page"><section class="glass-card full-card"><h3>Turnos y áreas asignadas</h3><div class="table-wrap"><table class="data-table"><thead><tr><th>Fecha</th><th>Horario</th><th>Alberca</th><th>Área</th><th>Empleado</th></tr></thead><tbody><?php foreach($turnos as $x): ?><tr><td><?= e($x['fecha']) ?></td><td><?= e(substr($x['hora_inicio'],0,5)) ?> - <?= e(substr($x['hora_fin'],0,5)) ?></td><td><?= e($x['alberca']) ?></td><td><?= e($x['area']) ?></td><td><?= e($x['empleado']) ?></td></tr><?php endforeach; ?></tbody></table></div></section></div>
